import { _decorator, Component, director, game, Node } from 'cc';
import { StateMachine } from 'javascript-state-machine'
const { ccclass, property } = _decorator;

@ccclass('GameState')
export class GameState {
    static instance: GameState = null;
    _isPause: boolean = false;

    _music: boolean;
    _isShowPopup: boolean;
    _popupNode: Node;

    constructor() {
        console.log(director.getScene())
        this._music = true;
        this._isShowPopup = false;
        if (GameState.instance) {
            if (this.popupNode){
                this.setPopupParent();
                console.log('new p')
            }
            return GameState.instance;
        }
        this._isPause = false;
        GameState.instance = this;
    }

    get music(): boolean {
        return this._music;
    }

    set music(value: boolean) {
        this._music = value;
    }


    get popupNode(): Node {
        return this._popupNode;
    }

    set popupNode(value: Node) {
        this._popupNode = value;
        this._popupNode.active = false;
    }

    setPopupParent() {
        this._popupNode.parent = director.getScene().getChildByName('Canvas');
    }

    togglePopup() {
        this._isShowPopup = !this._isShowPopup;
    }

    togglePause() {
        this._isPause = !this._isPause;
    }

    destroy() {
        GameState.instance = null;
    }
}

GameState.instance = null;